import React, { useState, useEffect } from "react";
import { Button, Input, Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui";

const API_URL = "http://127.0.0.1:8000";

export default function InvoiceExtractor() {
  const [file, setFile] = useState(null);
  const [amount, setAmount] = useState("");
  const [category, setCategory] = useState("");
  const [date, setDate] = useState("");
  const [invoices, setInvoices] = useState([]);

  useEffect(() => {
    fetchInvoices();
  }, []);

  const handleFileUpload = (event) => {
    setFile(event.target.files[0]);
  };

  const uploadInvoice = async () => {
    if (!file || !amount || !category || !date) return;
    const formData = new FormData();
    formData.append("file", file);
    formData.append("amount", amount);
    formData.append("category", category);
    formData.append("date", date);

    const response = await fetch(`${API_URL}/upload/`, {
      method: "POST",
      body: formData,
    });
    if (response.ok) {
      fetchInvoices();
    }
  };

  const fetchInvoices = async () => {
    const response = await fetch(`${API_URL}/invoices/`);
    const data = await response.json();
    setInvoices(data.invoices);
  };

  const deleteInvoice = async (id) => {
    await fetch(`${API_URL}/delete/${id}`, { method: "DELETE" });
    fetchInvoices();
  };

  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-4">Invoice Extractor</h1>
      <div className="flex flex-col space-y-2 mb-4">
        <label className="font-semibold">Upload Invoice File:</label>
        <Input type="file" onChange={handleFileUpload} className="p-2 border rounded" />
        <label className="font-semibold">Amount:</label>
        <Input type="number" placeholder="Amount" value={amount} onChange={(e) => setAmount(e.target.value)} className="p-2 border rounded" />
        <label className="font-semibold">Category:</label>
        <Input type="text" placeholder="Category" value={category} onChange={(e) => setCategory(e.target.value)} className="p-2 border rounded" />
        <label className="font-semibold">Date:</label>
        <Input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="p-2 border rounded" />
        <Button onClick={uploadInvoice} className="p-2 bg-blue-500 text-white rounded">Upload Invoice</Button>
      </div>
      
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>ID</TableHead>
            <TableHead>Filename</TableHead>
            <TableHead>Amount</TableHead>
            <TableHead>Date</TableHead>
            <TableHead>Order #</TableHead>
            <TableHead>Merchant</TableHead>
            <TableHead>Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {invoices.length > 0 ? (
            invoices.map((invoice) => (
              <TableRow key={invoice.id}>
                <TableCell>{invoice.id}</TableCell>
                <TableCell>{invoice.filename}</TableCell>
                <TableCell>${invoice.amount}</TableCell>
                <TableCell>{invoice.date}</TableCell>
                <TableCell>{invoice.order_number}</TableCell>
                <TableCell>{invoice.merchant}</TableCell>
                <TableCell>
                  <Button className="mr-2 bg-red-500 text-white p-1 rounded" onClick={() => deleteInvoice(invoice.id)}>Delete</Button>
                  <Button className="bg-green-500 text-white p-1 rounded">Edit</Button>
                </TableCell>
              </TableRow>
            ))
          ) : (
            <TableRow>
              <TableCell colSpan="7" className="text-center">No invoices found</TableCell>
            </TableRow>
          )}
        </TableBody>
      </Table>
    </div>
  );
}
